// Get current datetime to determine the past week timeframe
const now = await api.getCurrentDatetime();
const oneWeekAgo = new Date(now.now.getTime() - 7 * 24 * 60 * 60 * 1000);

// Format dates as ISO strings for the API
const fromIso = oneWeekAgo.toISOString();
const toIso = now.now.toISOString();

// Get all transactions from the past week
const txResult = await api.listTransactionsInWindow({ fromIso, toIso };
const transactions = txResult.transactions;

// Get all customers to map IDs to names
const allCustomers = await api.getAllCustomers{ limit: 1000 };
const customerMap = new Map(allCustomers.customers.map(c => [c.id, c.name]));

// Group transactions by customer and find the customer with most transactions
const customerCounts = new Map<string, number>();
let maxTransactions = 0;
let topCustomerId = '';

for (const tx of transactions) {
  const count = (customerCounts.get(tx.customerId) || 0) + 1;
  customerCounts.set(tx.customerId, count);
  if (count > maxTransactions) {
    maxTransactions = count;
    topCustomerId = tx.customerId;
  }
}

const topCustomerName = customerMap.get(topCustomerId) || 'Unknown';

// Calculate spend stats for the top customer
const spendStats = await api.computeCustomerSpendStats{ 
  customerId: topCustomerId, 
  fromIso, 
  toIso 
};

// Return the required information
{
  topCustomerId: topCustomerId,
  topCustomerName: topCustomerName,
  transactionCount: maxTransactions,
  totalSpend: spendStats.totalSpend,
  averageSpend: spendStats.averageSpend,
  fromIso: fromIso,
  toIso: toIso
}

